const body = $input.all()[0].json.body;
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!uuidRegex.test(body.tenantId)) {
  throw new Error('Invalid tenantId format');
}

if (!uuidRegex.test(body.archiveId)) {
  throw new Error('Invalid archiveId format');
}

return {
  tenantId: body.tenantId,
  archiveId: body.archiveId
};

const crypto = require('crypto');
const archive = $input.all()[0]?.json?.[0];

if (!archive) {
  throw new Error('Archive not found');
}

const today = new Date();
const expirationDate = new Date(archive.date_expiration);
const isExpired = today > expirationDate;

const data = archive.type_document + archive.reference_document + archive.annee_fiscale + archive.date_archivage;
const recalculatedHash = crypto.createHash('sha256').update(data).digest('hex');
const hashValid = recalculatedHash === archive.hash_integrite;

return {
  ...($json),
  archive: archive,
  hashValid: hashValid,
  isExpired: isExpired,
  recalculatedHash: recalculatedHash,
  storedHash: archive.hash_integrite
};

const result = $input.all()[0]?.json?.[0] || {};

return {
  success: $json.hashValid && !$json.isExpired,
  archiveId: $json.archiveId,
  verification: {
    hashValid: $json.hashValid,
    isExpired: $json.isExpired,
    status: result.statut,
    verifiedAt: new Date().toISOString()
  },
  details: {
    type: $json.archive?.type_document,
    reference: $json.archive?.reference_document,
    annee: $json.archive?.annee_fiscale,
    dateExpiration: $json.archive?.date_expiration
  }
};
